        if (isTrue(exchange.safeBool(exchange.has, "prediction", false)))
        {
            skippedProperties = exchange.extend(new Dictionary<string, object>() {
                { "symbol", true },
                { "timestamp", true },
                { "datetime", true },
                { "leverage", true },
                { "initialMargin", true },
                { "initialMarginPercentage", true },
                { "maintenanceMargin", true },
