                { "entryPrice", true },
                { "notional", true },
                { "unrealizedPnl", true },
                { "marginRatio", true },
                { "liquidationPrice", true },
                { "markPrice", true },
                { "collateral", true },
                { "percentage", true },
            }, skippedProperties);
        }
        object format = new Dictionary<string, object>() {
            { "info", new Dictionary<string, object>() {} },
            { "symbol", "XYZ/USDT" },
            { "timestamp", 1504224000000 },
            { "datetime", "2017-09-01T00:00:00" },
            { "initialMargin", exchange.parseNumber("1.234") },
